var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 봐, 빌딩에 불이 붙었어!","JPN":"見て、あそこ！　ビルに火がついたぞ！","ENG":"Look, over there! The building's on fire!","TWN":"大家快看，大樓失火啦！"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"알파트릭스 건물이다! 뭐 해, 어서 찍어!","JPN":"アルファトリックスの建物だ！　何してんだ、早く撮れ！","ENG":"It's the Alphatrix building! What are you doing? We have to film it!","TWN":"是阿爾法崔克斯的大樓！還不趕快拍下來！"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"가스라도 폭발했나……? 누가 신고해야 하는 거 아냐?","JPN":"ガスでも爆発したのかな……？　誰か通報した方がよくない？","ENG":"Did they have a gas leak...? Hasn’t anyone called the police yet?","TWN":"是瓦斯氣爆嗎……？是不是該報警？"},"stage":{"bg":"MAINSTREAM_000008","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"콜록……! 군용 폭발물이라도 입수했나? 어떻게 이렇게까지……?","JPN":"ゲホッ……！　軍用の爆発物でも入手したのかな？　なんでここまで……？","ENG":"*Cough...!* Did they get their hands on some military grade explosives? How did they even...?","TWN":"咳咳……！是軍隊在用的炸彈嗎？威力也太大……？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이진 씨, 강소영 경위입니다! 안에 계신가요!","JPN":"シノザキ・ホノカさん、マエカワ・ナツミ警部補です！　中にいますか！","ENG":"Miss Lee? It's Lieutenant Kang! Are you in there?!","TWN":"李珍小姐，我姜素英警官！你在裡面嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"살아 있다면 대답하세요! 어서요!","JPN":"生きているなら返事してください！　早く！","ENG":"Say something if you're still there! Please!","TWN":"你還活著的話請回答！快說話！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"여기……. 이쪽입니다…….","JPN":"こち……こちらです……","ENG":"I'm... Over here...","TWN":"我……在這裡……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"구조대가 곧 올 거예요. 부축해 드리겠습니다.","JPN":"もうすぐ救助隊が到着します。肩をお貸しします。","ENG":"The rescue team is on their way. Here, let me help you.","TWN":"消防員很快就會抵達這裡，我扶你。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"잠시 정신을 잃긴 했지만…… 그래도 병원 신세를 질 만큼 다친 건 아니에요.","JPN":"しばらく気を失ってはいましたが……それでも病院に行くほどの怪我ではありません。","ENG":"I was knocked out for a few minutes, but... I don't think I’ll need to visit the hospital.","TWN":"我是有稍微失去意識……但還沒嚴重到需要進醫院的程度。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이쪽의 근육 바보 먼저 챙겨 줘. 팔다리 한 짝씩 예쁘게 부러졌어.","JPN":"こっちの筋肉バカから助けてもらえるかしら。腕と足一本ずつキレイに折れてるわ。","ENG":"Take care of this musclehead. He broke an arm and a leg.","TWN":"先救救這個肌肉傻瓜吧，四肢斷得很徹底。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"근육 바보라니! 아야야야……!","JPN":"筋肉バカって！　あたたた……！","ENG":"Musclehead?! Ouch...!","TWN":"你說誰是肌肉傻瓜！哎呀呀呀呀……！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"카운터가 있는 줄 알았다면 위험을 감수해서라도 최대한 빠르게 제압했을 거예요.","JPN":"カウンターがいることを知っていれば、危険を冒してでもなるべく早く制圧しようとしたはずです。","ENG":"If I had known they had a Counter, I would have taken them on as quickly as possible, despite the risks.","TWN":"早知道當中有制裁者，就算冒著危險也要儘速壓制他們才對。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"모두 제 불찰입니다.","JPN":"すべて私のミスです。","ENG":"It's all my fault.","TWN":"都是我的疏失。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"카운터요? 방금 제가 제대로 들은 거 맞나요?","JPN":"カウンターですか？　今の私の聞き間違いじゃないですよね？","ENG":"A Counter? Did I hear that right?","TWN":"制裁者？我有聽錯嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 용병 분들이 다른 두 명을 견제하는 동안, 제가 제압하려 했던 여성 민병대원이 손에서 불길을 일으키더군요.","JPN":"はい。傭兵の方々が他の二人をマークしている間、私が女性の民兵隊員を制圧しようとしたのですが、その者の手から炎が出たのです。  ","ENG":"Yes. While our mercenaries were dealing with the other two, the girl I was fighting had fire coming out of her hands.","TWN":"沒錯，傭兵在對付其中二名隊員時，我負責的那名女性民兵隊員手上有火苗。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저도 불을 다루는 데 나름 조예가 있는 편입니다.","JPN":"私も炎を扱うことについてはそれなりに自信のある方です。","ENG":"You see, I'm also familiar with handling fire.","TWN":"我個人對火的事也是略懂略懂。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};